sql:
SELECT AVG(d.age) AS average_donor_age
FROM donors d
JOIN samples s ON d.donor_id = s.donor_id;

SELECT organism_part
FROM samples
WHERE organism = 'human' AND source_name = 'Oxford University';

SELECT sample_id
FROM assays
WHERE assay_name = 'Some Assay Name';

SELECT DISTINCT donor_name
FROM donors
WHERE age > 50;

SELECT disease
FROM samples
WHERE sample_id = 1;

SELECT t.*, s.*
FROM treatments t
LEFT JOIN samples s ON t.sample_id = s.sample_id;

external_knowledge:
- 'experiments' refers to research activities aimed at testing hypotheses or exploring phenomena; 
- 'assays' pertain to systematic procedures employed for testing or analyzing samples; 
- 'modification parameters' are adjustable settings or values that can alter the outcome of an assay.
